```(async function() {
    'use strict';

    console.log('🔍 开始搜索政策文件下载链接...');

    // 1. 寻找并过滤下载链接
    const downloadLinks = Array.from(document.querySelectorAll('a[href]'))
        .map(a => a.href)
        // 排除掉 javascript:void(0) 这种无效链接
        .filter(href => !href.startsWith('javascript:')) 
        .filter(href => {
            // 增加 wps 支持：以 .doc、.docx 或 .wps 结尾（允许后面带 ? 参数或 # 锚点）
            const isDocRegex = /\.(doc|docx|wps)(?:$|\?|#)/i;
            return href.includes('/document/download?') || isDocRegex.test(href);
        });

    const uniqueLinks = [...new Set(downloadLinks)];

    console.log(`📊 找到 ${uniqueLinks.length} 个可能的下载链接:`);
    uniqueLinks.forEach((link, i) => console.log(`   ${i+1}: ${link}`));

    if (uniqueLinks.length === 0) {
        console.warn('⚠️ 未找到下载链接。

```
{选股名称：回踩20线_大师进阶版}

{1. 基础均线系统}
MA20 := MA(C, 20);
MA60 := MA(C, 60);
MA120 := MA(C, 120);

{2. 涨停基因 (30天内)}
ZT := (C/REF(C,1) >= 1.095) AND (C = H);
ZT_COUNT := COUNT(ZT, 30);
COND_GENE := ZT_COUNT >= 1 AND ZT_COUNT <= 3; {放宽到3次，包容妖股}

{3. 位置回踩}
COND_POS := ABS((C - MA20) / MA20) <= 0.025; {稍微放宽到2.5%，防止错失}

{4. ★进阶1：长期趋势保护 (多头排列)}
{20线在60线之上，且60线不能向下拐头太厉害}
COND_TREND := MA20 > MA60 AND MA60 > REF(MA60, 5);

{5. ★进阶2：极致缩量 (相比涨停日)}
{获取最近一次涨停距今的天数}
DAYS_LAST_ZT := BARSLAST(ZT);
{那天的成交量}
VOL_AT_ZT := REF(VOL, DAYS_LAST_ZT);
{今天的量 < 涨停量的0.6倍 (即缩量4成以上)}
COND_PVOL := VOL < VOL_AT_ZT * 0.6 AND VOL < REF(VOL, 1);

{6. ★进阶3：相对强度 (跑赢大盘)}
MY_RPS := (C - REF(C, 10)) / REF(C, 10);
INDEX_RPS := (INDEXC - REF(INDEXC, 10)) / REF(INDEXC, 10);
COND_STRONG := MY_RPS > INDEX_RPS;

{7. 辅助指标 (筹码 + MACD)}
COND_WIN := WINNER(C)*100 > 60;
DIF := EMA(C, 12) - EMA(C, 26);
COND_MACD := DIF > -0.1; {允许轻微跌破0轴，只要趋势没崩}

{8. 安全过滤}
NO_ST := NAMELIKE('ST')=0 AND NAMELIKE('*ST')=0 AND DYNAINFO(4)>0;
NO_BAD := C/REF(C,1) > 0.91;

{----最终输出----}
XG: COND_GENE AND COND_POS AND COND_TREND AND COND_PVOL AND COND_STRONG AND COND_WIN AND COND_MACD AND NO_ST AND NO_BAD;
```。

```
{威科夫猎手 - 主图指标}

{1. 基础均线系统 - 定义趋势背景}
MA20:MA(C,20),COLORRED,LINETHICK2; {生命线，红色}
MA60:MA(C,60),COLORBLUE,LINETHICK1; {趋势线，蓝色}

{2. 关键量能定义}
MAVOL:=MA(V,20);
倍量:=V>=MAVOL*1.8; {成交量是20日均量的1.8倍以上}
缩量:=V<=MAVOL*0.6; {成交量萎缩}

{3. 威科夫买点逻辑}

{逻辑A: 强势回踩 (LPS - LAST POINT OF SUPPORT)}
{条件：趋势向上 + 回踩MA20不破 + 缩量 + 收阳}
LPS条件:=MA20>REF(MA20,1) AND L<=MA20 AND C>MA20 AND 缩量 AND C>O;
DRAWTEXT(LPS条件,L*0.98,'LPS'),COLORYELLOW;
DRAWICON(LPS条件,L*0.98,1); {黄色笑脸图标}

{逻辑B: 强势突破 (JOC - JUMP OVER CREEK)}
{条件：一根大阳线放量突破MA20，且MA20走平或向上}
JOC条件:=CROSS(C,MA20) AND 倍量 AND C/REF(C,1)>1.03 AND MA20>=REF(MA20,1);
DRAWTEXT(JOC条件,L*0.96,'JOC'),COLORMAGENTA;
DRAWICON(JOC条件,L*0.96,25); {红色箭头图标}

{逻辑C: 弹簧效应 (SPRING) - 左侧博弈}
{条件：创20日新低 + 收盘收回 + 长下影线}
LL:=LLV(L,20);
下影线:=(MIN(O,C)-L)/(H-L)>0.4; {下影线长度超过K线总长的40%}
SPRING条件:=L<=LL AND C>LL AND 下影线 AND C>O;
DRAWTEXT(SPRING条件,L*0.95,'SPRING'),COLORWHITE;

{4. 威科夫卖点逻辑}

{逻辑D: 上冲回落 (UT - UPTHRUST)}
{条件：创20日新高 + 收盘下跌或长上影 + 巨量/高位滞涨}
HH:=HHV(H,20);
上影线:=(H-MAX(O,C))/(H-L)>0.4;
UT条件:=H>=HH AND (C<O OR 上影线) AND V>MAVOL;
DRAWTEXT(UT条件,H*1.02,'UT'),COLORGREEN;
DRAWICON(UT条件,H*1.02,2); {绿色苦脸图标}

{逻辑E: 弱势信号 (SOW - SIGN OF WEAKNESS)}
{条件：有效跌破MA20 + 阴线}
SOW条件:=CROSS(MA20,C) AND C<O;
DRAWICON(SOW条件,H*1.01,27); {绿色箭头图标};
```。

```
{--- 上涨逻辑 ---}
A1:=C>REF(C,4);
NT:=BARSLASTCOUNT(A1);
TJ11:=NT=9;
DIST9:=BARSLAST(TJ11);
TJ13:=ISLASTBAR AND NT>=5 AND NT<=8;
AY:=(BACKSET(TJ11>0,9) OR BACKSET(TJ13>0,NT))*NT;

{上涨计数1-8显示为洋红色}
DRAWTEXT(AY=1,H*1.01,'1'),COLORMAGENTA;
DRAWTEXT(AY=2,H*1.01,'2'),COLORMAGENTA;
DRAWTEXT(AY=3,H*1.01,'3'),COLORMAGENTA;
DRAWTEXT(AY=4,H*1.01,'4'),COLORMAGENTA;
DRAWTEXT(AY=5,H*1.01,'5'),COLORMAGENTA;
DRAWTEXT(AY=6,H*1.01,'6'),COLORMAGENTA;
DRAWTEXT(AY=7,H*1.01,'7'),COLORMAGENTA;
DRAWTEXT(AY=8,H*1.01,'8'),COLORMAGENTA;

{上涨计数9及后续显示为绿色}
DRAWTEXT(DIST9=0,H*1.01,'9'),COLORGREEN;
DRAWTEXT(DIST9=1,H*1.01,'10'),COLORGREEN;
DRAWTEXT(DIST9=2,H*1.01,'11'),COLORGREEN;
DRAWTEXT(DIST9=3,H*1.01,'12'),COLORGREEN;
DRAWTEXT(DIST9=4,H*1.01,'13'),COLORGREEN;

{--- 下跌逻辑 ---}
B1:=C<REF(C,4);
NT0:=BARSLASTCOUNT(B1);
TJ21:=NT0=9;
DIST09:=BARSLAST(TJ21);
TJ23:=ISLASTBAR AND NT0>=5 AND NT0<=8;
AY1:=(BACKSET(TJ21>0,9) OR BACKSET(TJ23>0,NT0))*NT0;

{下跌计数1-8显示为绿色}
DRAWTEXT(AY1=1,H*1.01,'1'),COLORGREEN;
DRAWTEXT(AY1=2,H*1.01,'2'),COLORGREEN;
DRAWTEXT(AY1=3,H*1.01,'3'),COLORGREEN;
DRAWTEXT(AY1=4,H*1.01,'4'),COLORGREEN;
DRAWTEXT(AY1=5,H*1.01,'5'),COLORGREEN;
DRAWTEXT(AY1=6,H*1.01,'6'),COLORGREEN;
DRAWTEXT(AY1=7,H*1.01,'7'),COLORGREEN;
DRAWTEXT(AY1=8,H*1.01,'8'),COLORGREEN;

{下跌计数9及后续显示为洋红色}
DRAWTEXT(DIST09=0,H*1.01,'9'),COLORMAGENTA;
DRAWTEXT(DIST09=1,H*1.01,'10'),COLORMAGENTA;
DRAWTEXT(DIST09=2,H*1.01,'11'),COLORMAGENTA;
DRAWTEXT(DIST09=3,H*1.01,'12'),COLORMAGENTA;
DRAWTEXT(DIST09=4,H*1.01,'13'),COLORMAGENTA;
```。
